import React, { useState, useEffect, useRef, useCallback } from 'react';

function ScrollTracker() {
    const [scrollY, setScrollY] = useState(0);
    const [scrollDirection, setScrollDirection] = useState('none');

    // Use ref to track previous scroll position without causing re-renders
    const lastScrollYRef = useRef(0);

    // Named handler functions for stable references
    const handleScroll = useCallback(() => {
        const currentScrollY = window.scrollY;
        const lastY = lastScrollYRef.current;

        setScrollDirection(currentScrollY > lastY ? 'down' : 'up');
        lastScrollYRef.current = currentScrollY;
        setScrollY(currentScrollY);
    }, []);

    const handleResize = useCallback(() => {
        console.log('Window resized, recalculating...');
        setScrollY(window.scrollY);
    }, []);

    useEffect(() => {
        // Attach named handlers
        window.addEventListener('scroll', handleScroll);
        window.addEventListener('resize', handleResize);

        // Cleanup on unmount or before effect re-runs
        return () => {
            window.removeEventListener('scroll', handleScroll);
            window.removeEventListener('resize', handleResize);
        };
    }, [handleScroll, handleResize]); // Stable due to useCallback with empty deps

    return (
        <div style={{ position: 'fixed', top: 10, right: 10, padding: '10px', background: '#333', color: '#fff' }}>
            <p>Scroll Y: {scrollY}</p>
            <p>Direction: {scrollDirection}</p>
        </div>
    );
}

export default ScrollTracker;
```

### Key Fixes Applied

| Problem | Fix |
|---------|-----|
| No deps array | Empty deps via stable `useCallback` handlers |
| No cleanup | Return removal function from `useEffect` |
| Anonymous functions | Named handlers via `useCallback` |
| Stale `lastScrollY` | Moved to `useRef` (no re-render, always current) |
| Strict Mode double-invoke | Cleanup removes listeners before second setup |

